// src/firebase/firebaseService.js
import { db } from "./firebaseConfig";
import {
  ref,
  onValue,
  set,
  push,
  update,
  remove,
  get,
} from "firebase/database";

/* ───────────────── SUBSCRIBE TO SCORES (real-time) ───────────────── */
export function subscribeToScores(callback) {
  const scoresRef = ref(db, "users");
  const unsub = onValue(scoresRef, (snapshot) => {
    callback(snapshot.val() || {});
  });
  return unsub;
}

/* ───────────────── SCORES ───────────────── */
export async function getScores() {
  const snapshot = await get(ref(db, "users"));
  const data = snapshot.val() || {};
  return Object.entries(data)
    .map(([uid, d]) => ({ uid, ...d }))
    .sort((a, b) => (b.totalPoints || 0) - (a.totalPoints || 0));
}

/* ───────────────── USERS ───────────────── */
export async function addUser(name) {
  const usersRef = ref(db, "users");
  const snapshot = await get(usersRef);
  const users = snapshot.val() || {};

  // Check if user already exists
  const existing = Object.entries(users).find(
    ([, u]) => u.name.toLowerCase() === name.toLowerCase()
  );
  if (existing) return { uid: existing[0], name };

  const newRef = push(usersRef);
  await set(newRef, { name, totalPoints: 0, taskCount: 0 });
  return { uid: newRef.key, name };
}

export async function getUsers() {
  const snapshot = await get(ref(db, "users"));
  const data = snapshot.val() || {};
  return Object.entries(data).map(([uid, u]) => ({ uid, ...u }));
}

/* ───────────────── TASKS ───────────────── */
export async function getTasks() {
  const snapshot = await get(ref(db, "tasks"));
  const data = snapshot.val() || {};
  return Object.entries(data).map(([tid, d]) => ({ tid, ...d }));
}

export async function addTask(task) {
  const tasksRef = ref(db, "tasks");
  const points =
    task.customPoints ||
    CHORE_POINTS[task.title] ||
    10;
  const newRef = push(tasksRef);
  await set(newRef, {
    title: task.title,
    points,
    assignedTo: task.assignedTo,
    assignedName: task.assignedName,
    status: "pending",
    createdAt: Date.now(),
  });
  return { id: newRef.key, points };
}

export async function updateTask(tid, updates) {
  await update(ref(db, `tasks/${tid}`), updates);
}

export async function deleteTask(tid) {
  await remove(ref(db, `tasks/${tid}`));
}

export async function completeTask(taskId, userId, userName) {
  const taskSnap = await get(ref(db, `tasks/${taskId}`));
  const task = taskSnap.val();
  if (!task) return { success: false, message: "Task not found." };
  if (task.status === "completed")
    return { success: false, message: "Task already completed." };

  const points = task.points || 0;

  // Mark task completed
  await update(ref(db, `tasks/${taskId}`), {
    status: "completed",
    completedBy: userId,
    completedName: userName,
    completedAt: Date.now(),
  });

  // Update user score
  const userSnap = await get(ref(db, `users/${userId}`));
  const user = userSnap.val() || { name: userName, totalPoints: 0, taskCount: 0 };
  await update(ref(db, `users/${userId}`), {
    name: user.name || userName,
    totalPoints: (user.totalPoints || 0) + points,
    taskCount: (user.taskCount || 0) + 1,
  });

  return { success: true, pointsAwarded: points };
}

/* ───────────────── RESET ───────────────── */
export async function resetAllScores() {
  const snapshot = await get(ref(db, "users"));
  const users = snapshot.val() || {};
  const updates = {};
  Object.keys(users).forEach((uid) => {
    updates[`users/${uid}/totalPoints`] = 0;
    updates[`users/${uid}/taskCount`] = 0;
  });
  await update(ref(db), updates);
}

/* ───────────────── BADGE ───────────────── */
export function getBadge(points, status) {
  if (status === "Poor") return { label: "Needs Help 😢", color: "#f87171" };
  if (points >= 200) return { label: "Gold 🥇", color: "#facc15" };
  if (points >= 100) return { label: "Silver 🥈", color: "#c0c0c0" };
  if (points >= 50) return { label: "Bronze 🥉", color: "#cd7f32" };
  return { label: "Starter ⭐", color: "#60a5fa" };
}

/* ───────────────── CHORE POINTS ───────────────── */
export const CHORE_POINTS = {
  "Wash Dishes": 10,
  "Vacuum Living Room": 20,
  "Take Out Trash": 15,
  "Clean Bathroom": 25,
};
